import React, { useState, createContext, useContext } from 'react';

export type Theme = 'light' | 'night';

interface ThemeContent {
	themeOption: Theme;
	themeBgClassName: string;
	themeTextClassName: string;
}

interface ThemeContextProps {
  theme: ThemeContent;
  toggleTheme: () => void;
}

export const ThemeContext = createContext<ThemeContextProps>(
  {} as ThemeContextProps
);

export default function ThemeContextProvider({children}: any){
	const [theme, setTheme] = useState<ThemeContent>({themeOption: 'night', themeBgClassName: 'bg-slate-900', themeTextClassName: 'text-white'});

	const toggleTheme = () => {
		setTheme((theme) => (theme.themeOption === 'light' ? {themeOption: 'night', themeBgClassName: 'bg-slate-900', themeTextClassName: 'text-white'} : {themeOption: 'light', themeBgClassName: 'bg-slate-300', themeTextClassName: 'text-slate-600'}));
		console.log('theme');
	};

	return (
		<ThemeContext.Provider value={{ theme, toggleTheme }}>
			{children}
		</ThemeContext.Provider>
	);
};

export function useTheme() {
	const { theme, toggleTheme } = useContext(ThemeContext);
	return { theme, toggleTheme };
}
